+// reloadConfigTransactional stops on the first failed reloader and restores the
+// complete last-known-good configuration when any new configuration was applied.
+func reloadConfigTransactional(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), lastKnown *config.Config, status *web.ReloadStatus, rls ...reloader) (conf *config.Config, err error) {
+	outcome := api_v1.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339Nano), AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+			outcome.LastReloadSuccessful = true
+			outcome.ErrorCategory = "none"
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+		if status != nil {
+			status.Record(outcome)
+		}
+	}()
+
+	logger.Info("Loading configuration file", "filename", filename)
+	conf, err = loadConfig(filename, enableExemplarStorage, logger)
+	if err != nil {
+		outcome.ErrorCategory, outcome.ErrorMessage = "load_error", err.Error()
+		return nil, err
+	}
+	for _, rl := range rls {
+		started := time.Now()
+		err = rl.reloader(conf)
+		outcome.ReloaderTimingsMS[rl.name] = time.Since(started).Milliseconds()
+		if err != nil {
+			outcome.ErrorCategory, outcome.ErrorMessage, outcome.FailedReloader = "apply_error", err.Error(), rl.name
+			if len(outcome.AppliedReloaders) > 0 && lastKnown != nil {
+				outcome.RollbackAttempted = true
+				outcome.RollbackSuccessful = true
+				for _, rollback := range rls {
+					if rollbackErr := rollback.reloader(lastKnown); rollbackErr != nil {
+						outcome.RollbackSuccessful = false
+						outcome.ErrorCategory = "rollback_error"
+						outcome.ErrorMessage = rollbackErr.Error()
+						break
+					}
+				}
+			}
+			return nil, fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, err)
+		}
+		outcome.AppliedReloaders = append(outcome.AppliedReloaders, rl.name)
+	}
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	return conf, nil
+}
